const leads = $input.first().json.result || [];

const byStatus = {};
leads.forEach(l => {
  const s = l.STATUS_ID || 'UNKNOWN';
  byStatus[s] = (byStatus[s] || 0) + 1;
});

const total    = leads.length;
const inSeq    = byStatus['IN_SEQUENCE'] || 0;
const closers  = byStatus['IN_PROCESS']  || 0;
const cold     = byStatus['COLD']        || 0;
const stealth  = byStatus['STEALTH']     || 0;
const inactive = byStatus['INACTIVE']    || 0;

// Taxa de conversão SDR→Closer
const convRate = total > 0 ? ((closers / total) * 100).toFixed(1) : 0;

// Leads respondendo (UF_WARMER_COUNT > 0)
const responderam = leads.filter(l => parseInt(l.UF_WARMER_COUNT || '0') > 0).length;
const respRate = inSeq > 0 ? ((responderam / inSeq) * 100).toFixed(1) : 0;

const metrics = {
  total, in_sequence: inSeq, closers, cold, stealth, inactive,
  taxa_conversao_pct: convRate,
  taxa_resposta_pct: respRate,
  by_status: byStatus,
  data_hora: new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' })
};

return [{ json: metrics }];

