const rawText = $input.first().json.content?.[0]?.text?.trim() || '{}';
let forecast = {};
try {
  const match = rawText.match(/\{[\s\S]*\}/);
  forecast = match ? JSON.parse(match[0]) : {};
} catch(e) {
  forecast = { fechamentos_estimados_semana: 0, gargalo_principal: 'Análise indisponível', acao_prioritaria: 'Revisar dados', alerta: e.message };
}
const metrics = $('Compute Metrics').first().json;
return [{ json: { ...metrics, forecast } }];

